// 從 flow context 中獲取當前篩選條件
const filters = flow.get('filters') || {
    department: null,
    status: null
};

// 輸出當前過濾條件到日誌
node.warn(`應用篩選條件: ${JSON.stringify(filters)}`);

// 將篩選條件設置為消息負載
msg.payload = filters;

return msg;

// 從消息負載中獲取篩選條件
const filters = msg.payload;
const department = filters.department;
const status = filters.status;

// 根據資料庫結構調整狀態值的映射
let statusValue = null;
if (status) {
    switch (status) {
        case 'available':
            statusValue = '可用';
            break;
        case 'occupied':
            statusValue = '佔用';
            break;
        case 'cleaning':
            statusValue = '待清潔';
            break;
        case 'maintenance':
            statusValue = '維修';
            break;
    }
}

// 構建基本查詢語句
let query = `
SELECT b.*, p.name as patient_name, p.id_number, p.age, p.gender 
FROM beds b 
LEFT JOIN patients p ON b.patient_id = p.patient_id
`;

// 添加篩選條件
let conditions = [];
if (department) {
    conditions.push(`b.department = '${department}'`);
}
if (statusValue) {
    conditions.push(`b.status = '${statusValue}'`);
}

// 如果有篩選條件，添加 WHERE 子句
if (conditions.length > 0) {
    query += ` WHERE ${conditions.join(' AND ')}`;
}

// 添加排序
query += ` ORDER BY b.department, b.floor, b.room_number, b.bed_number`;

// 添加限制，避免返回過多數據
query += ` LIMIT 1000`;

// 設置為消息主題（用於 MySQL 節點）
msg.topic = query;

// 記錄查詢語句
node.warn(`執行查詢: ${query}`);

return msg;

try {
    // 獲取查詢結果
    const beds = msg.payload || [];

    // 記錄接收到的數據量
    node.warn(`收到 ${beds.length} 筆病床資料`);

    // 初始化統計數據
    const stats = {
        available: 0,
        occupied: 0,
        cleaning: 0,
        maintenance: 0
    };

    // 初始化分組數據
    const groupedBeds = {};

    // 處理每一筆病床數據
    beds.forEach(bed => {
        // 建立位置標識（樓層+科室）
        const location = `${bed.floor}樓 ${bed.department}`;

        // 如果此位置尚未初始化，則建立
        if (!groupedBeds[location]) {
            groupedBeds[location] = [];
        }

        // 根據狀態設置顏色和圖標
        let color, icon, statusText, statusCode;

        // 根據資料庫的中文狀態值映射到英文代碼和顯示文字
        switch(bed.status) {
            case '可用':
                statusCode = 'available';
                statusText = '可用';
                color = '#4CAF50';
                icon = 'check_circle';
                stats.available++;
                break;
            case '佔用':
                statusCode = 'occupied';
                statusText = '佔用';
                color = '#F44336';
                icon = 'person';
                stats.occupied++;
                break;
            case '待清潔':
                statusCode = 'cleaning';
                statusText = '待清潔';
                color = '#FFC107';
                icon = 'cleaning_services';
                stats.cleaning++;
                break;
            case '維修':
                statusCode = 'maintenance';
                statusText = '維修中';
                color = '#9E9E9E';
                icon = 'build';
                stats.maintenance++;
                break;
            default:
                statusCode = 'unknown';
                statusText = '未知';
                color = '#2196F3';
                icon = 'help';
        }

        // 格式化病床資料
        const formattedBed = {
            id: bed.bed_id,
            code: bed.bed_code || `${bed.room_number}-${bed.bed_number}`,
            patientName: bed.patient_name || '空床',
            medicalRecordNumber: bed.medical_record_number,
            status: statusText,
            statusCode: statusCode,
            color: color,
            icon: icon,
            department: bed.department,
            floor: bed.floor
        };

        // 添加到對應的位置組
        groupedBeds[location].push(formattedBed);
    });

    // 構建最終輸出
    msg.payload = {
        stats: stats,
        groupedBeds: groupedBeds
    };

    // 記錄完成的分組數
    node.warn(`格式化完成，共 ${Object.keys(groupedBeds).length} 個位置分組`);

    return msg;
} catch (error) {
    // 錯誤處理
    node.error(`處理病床資料時發生錯誤: ${error.message}`);

    // 返回空資料
    msg.payload = {
        stats: { available: 0, occupied: 0, cleaning: 0, maintenance: 0 },
        groupedBeds: {},
        error: true,
        message: `處理資料時發生錯誤: ${error.message}`
    };

    return msg;
}

// 重置篩選條件
flow.set('filters', {
    department: null,
    status: null
});

// 記錄操作
node.warn('已重置所有篩選條件');

// 創建重置消息
msg.payload = {
    department: null,
    status: null
};

// 返回消息
return [msg, msg];

// 創建重置消息
const resetMsg = { payload: "" };

// 更新當前篩選條件顯示
const filterMsg = {
    payload: {
        department: null,
        status: null
    }
};

return [resetMsg, resetMsg, filterMsg];

// 建立啟動通知訊息
const notifyMsg = {
    topic: "system_startup",
    payload: {
        title: "病床管理系統已啟動",
        message: "系統已成功啟動並準備就緒"
    }
};

// 建立載入資料訊息
const loadMsg = {
    topic: "load_data",
    payload: {}
};

// 返回通知和載入訊息
return [notifyMsg, loadMsg];

// 提取標題和消息
if (msg.payload && msg.payload.title && msg.payload.message) {
    msg.topic = msg.payload.title;
    msg.payload = msg.payload.message;
}

return msg;

// 只處理病床選擇動作
if (msg.payload && msg.payload.action === 'select-bed') {
    // 獲取被選中的病床ID
    const bedId = msg.payload.bedId;

    // 建立查詢請求，確保明確包含 id_number 欄位
    msg.topic = `
    SELECT 
        b.*, 
        p.name as patient_name, 
        p.id_number,
        p.age,
        p.gender,
        p.department as patient_department,
        p.doctor,
        p.registration_date
    FROM beds b 
    LEFT JOIN patients p ON b.patient_id = p.patient_id
    WHERE b.bed_id = ${bedId}
    `;

    node.warn(`查詢病床詳情: ${bedId}, SQL: ${msg.topic}`);
    return msg;
}

// 其他請求不處理
return null;

// 取得查詢結果
const result = msg.payload;

// 記錄原始查詢結果（診斷用）
node.warn(`病床詳情查詢結果: ${JSON.stringify(result, null, 2)}`);

// 確保有查詢結果
if (result && result.length > 0) {
    const bedDetail = result[0];

    // 記錄 id_number 欄位（診斷用）
    node.warn(`病人 id_number: ${bedDetail.id_number}`);

    // 格式化病人資料
    let patientInfo = null;
    if (bedDetail.patient_id) {
        // 直接使用資料庫中的年齡欄位
        const age = bedDetail.age || '未知';

        // 計算住院天數
        let daysInHospital = '';
        if (bedDetail.admission_date) {
            const admissionDate = new Date(String(bedDetail.admission_date)); // 確保轉為字串
            const today = new Date();
            const diffTime = Math.abs(today.getTime() - admissionDate.getTime());
            daysInHospital = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
        }

        // 建立病人資訊物件，確保包含 id_number
        patientInfo = {
            name: bedDetail.patient_name,
            id_number: bedDetail.id_number, // 明確指定 id_number
            gender: bedDetail.gender || '未知',
            age: age,
            admissionDate: bedDetail.admission_date ? new Date(bedDetail.admission_date).toLocaleDateString() : '未知',
            dischargeDate: bedDetail.discharge_date ? new Date(bedDetail.discharge_date).toLocaleDateString() : '尚未出院',
            daysInHospital: daysInHospital || '未知',
            department: bedDetail.patient_department || bedDetail.department,
            doctor: bedDetail.doctor || '未指派'
        };
    }

    // 根據資料庫的中文狀態值映射到英文代碼和顯示文字
    let statusText, statusColor, statusCode;
    switch (bedDetail.status) {
        case '可用':
            statusText = '可用';
            statusColor = '#4CAF50';
            statusCode = 'available';
            break;
        case '佔用':
            statusText = '佔用';
            statusColor = '#F44336';
            statusCode = 'occupied';
            break;
        case '待清潔':
            statusText = '待清潔';
            statusColor = '#FFC107';
            statusCode = 'cleaning';
            break;
        case '維修':
            statusText = '維修中';
            statusColor = '#9E9E9E';
            statusCode = 'maintenance';
            break;
        default:
            statusText = '未知';
            statusColor = '#2196F3';
            statusCode = 'unknown';
    }

    // 格式化輸出
    msg.payload = {
        bed: {
            id: bedDetail.bed_id,
            code: bedDetail.bed_code || `${bedDetail.room_number}-${bedDetail.bed_number}`,
            floor: bedDetail.floor,
            department: bedDetail.department,
            status: statusText,
            statusCode: statusCode,
            statusColor: statusColor,
            roomNumber: bedDetail.room_number,
            bedNumber: bedDetail.bed_number,
            lastCleaned: bedDetail.last_cleaned ? new Date(bedDetail.last_cleaned).toLocaleString() : '未知'
        },
        patient: patientInfo
    };


    // 發送到詳情對話框
    return msg;
}

// 沒有查詢結果
msg.payload = {
    error: true,
    message: '未找到病床資料'
};
return msg;

// 獲取選擇的值
const selection = msg.payload || "";

// 如果是空值，不處理
if (!selection) {
    return null;
}

// 分解科別和醫師名稱 (格式是: "科別|醫師名")
const [department, doctor] = selection.split('|');

// 獲取現有的病患資料
const patientData = flow.get('patientData') || {};

// 更新科別和醫師資訊
patientData.department = department;
patientData.doctor = doctor;

// 儲存更新後的資料
flow.set('patientData', patientData);

// 記錄選擇
node.warn(`選擇科別: ${department}, 醫師: ${doctor}`);
node.warn(`更新後的病患資料: ${JSON.stringify(patientData)}`);

// 返回訊息以繼續流程
msg.payload = patientData;
return msg;

// 獲取所有患者資料
const patientData = flow.get('patientData') || {};

// 記錄當前資料狀態
node.warn(`準備登記的病患資料: ${JSON.stringify(patientData)}`);

// 檢查是否有必要的資料
if (!patientData.id_number || !patientData.name || 
    !patientData.age || !patientData.gender || 
    !patientData.department || !patientData.doctor) {

    // 記錄缺少的欄位
    const missing = [];
    if (!patientData.id_number) missing.push("身分證字號");
    if (!patientData.name) missing.push("姓名");
    if (!patientData.age) missing.push("年齡");
    if (!patientData.gender) missing.push("性別");
    if (!patientData.department) missing.push("科別");
    if (!patientData.doctor) missing.push("醫師");

    // 資料不完整
    const errorMessage = `請填寫所有必要資料，缺少: ${missing.join(", ")}`;
    node.warn(`登記失敗: ${errorMessage}`);

    msg.topic = "登記失敗";
    msg.payload = errorMessage;
    msg.highlight = "error";
    return [null, msg];
}

// 設置查詢語句來尋找合適的床位
msg.topic = `
SELECT bed_id, department, floor, room_number, bed_number
FROM beds
WHERE status = '可用' AND department = '${patientData.department}'
ORDER BY RAND()
LIMIT 1;
`;

// 儲存患者資料以便後續使用
flow.set('tempPatientData', patientData);

// 返回查詢訊息
return [msg, null];

// 清空病患資料
flow.set('patientData', {});
flow.set('tempPatientData', null);
flow.set('assignedBed', null);

// 建立重置表單的訊息
const resetFormMsg = {
    topic: "form_reset",
    payload: {
        id_number: "",
        name: "",
        age: "",
        gender: ""
    }
};

// 建立重置科別與醫師選單的訊息
const resetDoctorMsg = {
    topic: "reset_doctor",
    payload: ""
};

// 記錄重置操作
node.warn("表單已重置");

return [resetFormMsg, resetDoctorMsg];

// 清除之前的科別與醫師選擇
const existingData = flow.get('patientData') || {};

// 合併表單數據，保持基本資料但清除之前的科別與醫師資訊
const patientData = {
    ...msg.payload,
    department: null,
    doctor: null
};

// 儲存表單數據到 flow context
flow.set('patientData', patientData);

// 記錄操作
node.warn(`收到病患資料: ${JSON.stringify(patientData)}`);

// 將表單數據傳遞
msg.patient = patientData;
return msg;

// 獲取查詢結果
const beds = msg.payload;

// 獲取臨時保存的患者資料
const patientData = flow.get('tempPatientData') || {};

// 檢查是否找到可用床位
if (!beds || beds.length === 0) {
    // 沒有該科別的可用床位
    node.warn(`無法找到科別 ${patientData.department} 的可用床位`);

    // 仍然將病患資料保存，但不分配床位
    msg.topic = `
    INSERT INTO patients (
        id_number, 
        name, 
        age, 
        gender, 
        department, 
        doctor,
        registration_date
    ) VALUES (
        '${patientData.id_number}', 
        '${patientData.name}', 
        ${patientData.age}, 
        '${patientData.gender}', 
        '${patientData.department}', 
        '${patientData.doctor}',
        NOW()
    );
    `;

    // 構建通知訊息
    const notificationMsg = {
        topic: "登記成功但沒有床位",
        payload: `${patientData.name} 已成功登記到 ${patientData.department} ${patientData.doctor}醫師門診，但目前無可用床位`,
        highlight: "warning"
    };

    return [msg, notificationMsg];
}

// 獲取隨機分配的床位
const assignedBed = beds[0];
node.warn(`分配床位: ${JSON.stringify(assignedBed)}`);

// 更新床位狀態的SQL（將床位標記為佔用）
const updateBedSql = `
UPDATE beds
SET status = '佔用', patient_id = @patient_id
WHERE bed_id = ${assignedBed.bed_id};
`;

// 插入病患資料並獲取插入的ID
const insertPatientSql = `
INSERT INTO patients (
    id_number, 
    name, 
    age, 
    gender, 
    department, 
    doctor,
    registration_date,
    bed_id
) VALUES (
    '${patientData.id_number}', 
    '${patientData.name}', 
    ${patientData.age}, 
    '${patientData.gender}', 
    '${patientData.department}', 
    '${patientData.doctor}',
    NOW(),
    ${assignedBed.bed_id}
);
`;

// 設置SQL操作
msg.topic = insertPatientSql;

// 保存床位信息以供後續使用
flow.set('assignedBed', assignedBed);

// 構建通知訊息
const notificationMsg = {
    topic: "登記成功並分配床位",
    payload: `${patientData.name} 已成功登記到 ${patientData.department} ${patientData.doctor}醫師門診，並分配到 ${assignedBed.floor}樓 ${assignedBed.room_number}-${assignedBed.bed_number} 床位`,
    highlight: "success"
};

return [msg, notificationMsg];

// 獲取分配的床位信息
const assignedBed = flow.get('assignedBed');

// 檢查是否有分配床位
if (!assignedBed) {
    // 沒有分配床位，直接重置表單
    return [null, msg];
}

// 獲取插入的患者ID（如果資料庫返回）
let patientId = null;
if (msg.payload && msg.payload.insertId) {
    patientId = msg.payload.insertId;
}

// 如果沒有獲取到插入ID，使用臨時ID
if (!patientId) {
    patientId = 'LAST_INSERT_ID()';
}

// 建立更新床位的SQL語句
msg.topic = `
UPDATE beds
SET status = '佔用', patient_id = ${patientId}
WHERE bed_id = ${assignedBed.bed_id};
`;

return [msg, null];

// 處理病床狀態變更請求
if (msg.payload && msg.payload.action === 'change-status') {
    // 獲取請求參數
    const bedId = msg.payload.bedId;
    const newStatus = msg.payload.newStatus;

    if (!bedId || !newStatus) {
        // 如果參數不完整，返回錯誤
        node.error("狀態更新請求缺少必要參數");
        msg.payload = {
            error: true,
            message: "狀態更新失敗：缺少必要參數"
        };
        return msg;
    }

    // 根據英文狀態代碼映射到中文狀態值（資料庫使用中文狀態）
    let dbStatus;
    switch (newStatus) {
        case 'available':
            dbStatus = '可用';
            break;
        case 'occupied':
            dbStatus = '佔用';
            break;
        case 'cleaning':
            dbStatus = '待清潔';
            break;
        case 'maintenance':
            dbStatus = '維修';
            break;
        default:
            node.error(`無效的狀態代碼: ${newStatus}`);
            msg.payload = {
                error: true,
                message: `狀態更新失敗：無效的狀態代碼 ${newStatus}`
            };
            return msg;
    }

    // 構建SQL語句 - 針對不同操作
    let updateSQL = "";

    // 特殊處理出院操作
    if (newStatus === 'cleaning') {
        // 更新病床狀態為待清潔，並將patient_id設為NULL
        updateSQL = `
            UPDATE beds 
            SET status = '待清潔',
                patient_id = NULL
            WHERE bed_id = ${bedId}
        `;

        // 記錄操作
        node.warn(`執行出院操作：更新病床 ${bedId} 狀態為待清潔並清除病人關聯`);
    }
    // 如果狀態是打掃完畢，更新最近清潔時間
    else if (newStatus === 'available') {
        const currentTime = new Date().toISOString().slice(0, 19).replace('T', ' ');
        updateSQL = `
            UPDATE beds 
            SET status = '${dbStatus}', 
                last_cleaned = '${currentTime}' 
            WHERE bed_id = ${bedId}
        `;

        // 記錄操作
        node.warn(`執行病床狀態更新: ${bedId} -> ${dbStatus} 並更新清潔時間`);
    }
    // 其他普通狀態更新
    else {
        updateSQL = `
            UPDATE beds 
            SET status = '${dbStatus}' 
            WHERE bed_id = ${bedId}
        `;

        // 記錄操作
        node.warn(`執行普通病床狀態更新: ${bedId} -> ${dbStatus}`);
    }

    // 設置 SQL 查詢
    msg.topic = updateSQL;

    // 返回更新請求
    return [msg, null];
}
// 處理關閉詳情對話框請求
else if (msg.payload && msg.payload.action === 'close-detail') {
    // 簡單返回空消息以關閉對話框
    const closeMsg = { payload: {} };
    return [null, closeMsg];
}
// 其他未處理的請求
else {
    return [null, null];
}

// 獲取更新結果
const result = msg.payload;
const affectedRows = result ? result.affectedRows || 0 : 0;

// 根據結果建立消息
let notifyMsg, reloadMsg, clearDetailMsg;

// 檢查是否成功更新
if (affectedRows > 0) {
    // 創建成功通知消息
    notifyMsg = {
        topic: "狀態更新",
        payload: `病床狀態更新成功，影響 ${affectedRows} 筆記錄`
    };

    // 創建重新載入數據的消息
    reloadMsg = {
        topic: "refresh",
        payload: {}
    };

    // 創建清除詳情視圖的消息
    clearDetailMsg = {
        payload: {}
    };
} else {
    // 創建失敗通知消息
    notifyMsg = {
        topic: "狀態更新",
        payload: "病床狀態更新失敗，沒有記錄被更新"
    };

    // 不需要重新載入或清除視圖
    reloadMsg = null;
    clearDetailMsg = null;
}

// 返回消息
return [notifyMsg, reloadMsg, clearDetailMsg];

// 保存科室容量數據
msg.departmentCapacity = msg.payload;

// 準備查詢急診和ICU的特定數據
