// ---- 輔助函數 ----

// 日期格式化 YYYY-MM-DD
function formatDate(date) {
    const year = date.getFullYear();
    const month = String(date.getMonth() + 1).padStart(2, '0');
    const day = String(date.getDate()).padStart(2, '0');
    return `${year}-${month}-${day}`;
}

// 獲取兩個日期之間的週數差
function getWeekDifference(date1, date2) {
    const oneWeek = 7 * 24 * 60 * 60 * 1000;
    const firstDate = new Date(date1.getFullYear(), date1.getMonth(), date1.getDate());
    const secondDate = new Date(date2.getFullYear(), date2.getMonth(), date2.getDate());
    return Math.floor(Math.abs((firstDate.getTime() - secondDate.getTime())) / oneWeek);
}

// 獲取兩個日期之間的月數差
function getMonthDifference(date1, date2) {
    const months = (date1.getFullYear() - date2.getFullYear()) * 12;
    return months + date1.getMonth() - date2.getMonth();
}

// 處理科室統計的函數
function processDepartmentStats(bedsData) {
    const deptMap = {};
    const departments = [];
    const bedCounts = [];
    const occupancyRates = [];

    // 按科室分組
    bedsData.forEach(bed => {
        const dept = bed.department;
        if (!dept) return;

        if (!deptMap[dept]) {
            deptMap[dept] = { total: 0, occupied: 0 };
        }

        deptMap[dept].total++;
        if (bed.status === '佔用') {
            deptMap[dept].occupied++;
        }
    });

    // 轉換為數組格式
    for (const [dept, counts] of Object.entries(deptMap)) {
        departments.push(dept);
        bedCounts.push(counts.total);
        const rate = counts.total > 0 ? (counts.occupied / counts.total) * 100 : 0;
        occupancyRates.push(parseFloat(rate.toFixed(1)));
    }

    return { departments, bedCounts, occupancyRates };
}

// 處理樓層統計的函數
function processFloorStats(bedsData) {
    const floorMap = {};
    const floors = [];
    const bedCounts = [];
    const occupancyRates = [];

    // 按樓層分組
    bedsData.forEach(bed => {
        const floor = bed.floor;
        if (!floor) return;

        if (!floorMap[floor]) {
            floorMap[floor] = { total: 0, occupied: 0 };
        }

        floorMap[floor].total++;
        if (bed.status === '佔用') {
            floorMap[floor].occupied++;
        }
    });

    // 轉換為數組格式並排序
    const sortedFloors = Object.keys(floorMap).sort((a, b) => Number(a) - Number(b));

    sortedFloors.forEach(floor => {
        floors.push(`${floor}樓`);
        bedCounts.push(floorMap[floor].total);
        const rate = floorMap[floor].total > 0 ?
            (floorMap[floor].occupied / floorMap[floor].total) * 100 : 0;
        occupancyRates.push(parseFloat(rate.toFixed(1)));
    });

    return { floors, bedCounts, occupancyRates };
}

// 計算住院天數的函數 - 已修正版本
function calculateStayDays(patientsData) {
    const stayDays = [];

    patientsData.forEach(patient => {
        if (patient.registration_date) {
            // 如果有出院日期用出院日期，否則用當前日期
            const endDate = patient.discharge_date ? new Date(patient.discharge_date) : new Date();
            const startDate = new Date(patient.registration_date);

            // 計算住院天數
            const days = Math.round((endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24));
            if (days >= 0) stayDays.push(days);
        }
    });

    // 計算平均、最長、最短住院天數
    const avgStayDays = stayDays.length > 0 ?
        parseFloat((stayDays.reduce((sum, days) => sum + days, 0) / stayDays.length).toFixed(1)) : 0;

    const maxStayDays = stayDays.length > 0 ? Math.max(...stayDays) : 0;
    const minStayDays = stayDays.length > 0 ? Math.min(...stayDays) : 0;

    return { avgStayDays, maxStayDays, minStayDays };
}

// 準備本週統計的函數
function prepareWeeklyStats(patientsData) {
    const days = ['週一', '週二', '週三', '週四', '週五', '週六', '週日'];
    const admissions = [0, 0, 0, 0, 0, 0, 0];
    const discharges = [0, 0, 0, 0, 0, 0, 0]; // 出院數據暫無

    // 獲取本週的開始日期 (週一)
    const today = new Date();
    const dayOfWeek = today.getDay() === 0 ? 7 : today.getDay(); // 轉換為 1-7 表示週一到週日
    const mondayDate = new Date(today);
    mondayDate.setDate(today.getDate() - (dayOfWeek - 1));
    mondayDate.setHours(0, 0, 0, 0);

    // 從患者表獲取本週入院數據
    patientsData.forEach(patient => {
        if (patient.registration_date) {
            const registrationDate = new Date(patient.registration_date);

            // 只計算本週數據
            if (registrationDate >= mondayDate) {
                const dayIndex = registrationDate.getDay() === 0 ? 6 : registrationDate.getDay() - 1; // 0-6 對應週一到週日
                admissions[dayIndex]++;
            }
        }
    });

    return { days, admissions, discharges };
}

