// 處理科室佔用率數據分發給多個儀表盤
if (msg.payload && msg.payload.departments && msg.payload.departmentOccupancyRates) {
    const departments = msg.payload.departments;
    const occupancyRates = msg.payload.departmentOccupancyRates;

    // 創建儀表盤消息陣列，每個科室佔一個位置
    const output = [];

    // 將數據分配到9個輸出（對應9個不同的儀表盤）
    for (let i = 0; i < 9; i++) {
        if (i < departments.length) {
            // 為這個科室創建一個儀表盤消息
            output[i] = {
                topic: departments[i],
                payload: occupancyRates[i],
                deptName: departments[i]  // 用於顯示科室名稱
            };
        } else {
            // 如果沒有更多科室，傳遞空值
            output[i] = null;
        }
    }

    return output;
}

// 如果沒有數據，所有輸出都是null
return [null, null, null, null, null, null, null, null, null];
